login();
productos.forEach(producto => {
  cy.log(`Actualizando stock: ${producto.nombre}`);
  cy.visit('/odoo/inventory/products');
  cy.wait(2000);
  // Buscar producto
  cy.get('.o_searchbox input, input.o_searchbox_input').first().clear().type(producto.nombre);
  cy.get('.o_searchbox input, input.o_searchbox_input').first().type('{enter}');
  cy.wait(2000);
  // Abrir producto
  cy.get('.o_kanban_record, .o_data_row').first().click();
  cy.wait(2000);
  // Actualizar cantidad
  cy.contains('Actualizar cantidad').click();
  cy.wait(1500);
  // Ingresar cantidad
  cy.get('.o_field_widget[name="inventory_quantity"] input').first().clear().type(producto.stock);
  // Aplicar
  cy.contains('Aplicar todo').click({
    force: true
  });
  cy.wait(1500);
});

login();
clientes.forEach(cliente => {
  cy.log(`Creando cliente: ${cliente.nombre}`);
  cy.visit('/odoo/contacts/new');
  cy.get('.o_form_view').should('be.visible');
  cy.wait(1500);
  // Tipo persona
  cy.get('input[data-value="person"]').click({
    force: true
  });
  cy.wait(500);
  // Nombre
  cy.get('.o_field_widget[name="name"] input').clear().type(cliente.nombre);
  // Email
  cy.get('.o_field_widget[name="email"] input').clear().type(cliente.email);
  // Teléfono
  cy.get('.o_field_widget[name="phone"] input').clear().type(cliente.telefono);
  // Guardar
  cy.get('.o_form_button_save').click();
  cy.wait(1500);
});
